"use client";

import { useEffect, useState } from "react";
import { useSkills } from "@/lib/SkillContext";
import { RetentionEngine } from "@/lib/retention-engine";
import { Calendar, CheckCircle2, BookOpen, PenTool, Bot, Loader2, ArrowRight } from "lucide-react";
import Link from "next/link";

import { GlassCard } from "@/components/ui/GlassCard";

export default function PlannerPage() {
  const { skills, markPracticed } = useSkills();
  const { today, tomorrow, week } = RetentionEngine.getRevisionTasks(skills);
  const [briefing, setBriefing] = useState<{ briefing: string; recommendedAction: any } | null>(null);
  const [loadingContext, setLoadingContext] = useState(true);

  useEffect(() => {
    const fetchMentor = async () => {
      try {
        const res = await fetch("/api/mentor", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ skills }),
        });
        const data = await res.json();
        if (res.ok) setBriefing(data);
      } catch (e) {
        console.error("Mentor fetch error", e);
      } finally {
        setLoadingContext(false);
      }
    };
    if (skills.length > 0) fetchMentor();
    else setLoadingContext(false);
  }, [skills]);

  const TaskSection = ({ title, tasks, icon: Icon, emptyText }: {
    title: string;
    tasks: import("@/lib/types").RevisionTask[];
    icon: React.ComponentType<{ className?: string }>;
    emptyText: string;
  }) => (
    <GlassCard color="rgba(99, 102, 241, 0.2)" className="mb-6">
      <div className="flex items-center gap-2 mb-4">
        <Icon className="w-5 h-5 text-[var(--color-accent)]" />
        <h2 className="text-base font-bold text-white tracking-tight">{title}</h2>
        {tasks.length > 0 && (
          <span className="text-[10px] font-bold px-2.5 py-1 rounded-full bg-[var(--color-accent-muted)] text-[var(--color-accent)] shadow-sm">
            {tasks.length}
          </span>
        )}
      </div>

      {tasks.length === 0 ? (
        <div className="bg-black/20 border border-white/5 rounded-xl p-6 text-center shadow-inner">
          <p className="text-sm text-white/50">{emptyText}</p>
        </div>
      ) : (
        <div className="space-y-3">
          {tasks.map(task => {
            const statusColors: Record<string, string> = {
              healthy: "bg-[var(--color-green-muted)] text-[var(--color-green)] border border-[var(--color-green)]/20",
              review: "bg-[var(--color-yellow-muted)] text-[var(--color-yellow)] border border-[var(--color-yellow)]/20",
              decaying: "bg-[var(--color-red-muted)] text-[var(--color-red)] border border-[var(--color-red)]/20",
            };

            return (
              <div key={task.skillId} className="bg-white/5 border border-white/10 rounded-xl p-4 flex items-center justify-between hover:bg-white/10 transition-colors backdrop-blur-sm">
                <div className="flex items-center gap-4">
                  <div className="w-10 h-10 rounded-xl bg-black/40 border border-white/10 flex items-center justify-center shadow-inner">
                    {task.action === "quiz"
                      ? <PenTool className="w-4 h-4 text-[var(--color-accent)]" />
                      : <BookOpen className="w-4 h-4 text-[var(--color-accent)]" />
                    }
                  </div>
                  <div>
                    <div className="text-sm font-bold text-white">{task.skillName}</div>
                    <div className="flex items-center gap-2 mt-1">
                      <span className={`text-[10px] font-bold px-2 py-0.5 rounded shadow-sm ${statusColors[task.status]}`}>
                        {task.retentionScore}%
                      </span>
                      <span className="text-[11px] font-medium text-white/50 uppercase tracking-wider">
                        ~{task.estimatedMinutes} min ΓÇó {task.action === "quiz" ? "Take Quiz" : "Review Notes"}
                      </span>
                    </div>
                  </div>
                </div>

                <div className="flex items-center gap-2">
                  <Link
                    href={task.action === "quiz" ? `/quiz?skill=${task.skillId}` : `/study?skill=${task.skillId}`}
                    className="text-xs font-bold text-black bg-white hover:scale-105 px-4 py-2 rounded-lg transition-all shadow-[0_0_15px_rgba(255,255,255,0.2)]"
                  >
                    {task.action === "quiz" ? "Quiz" : "Study"}
                  </Link>
                  <button
                    onClick={() => markPracticed(task.skillId)}
                    className="p-2 bg-white/5 border border-white/10 hover:bg-green-500/20 hover:border-green-500/30 rounded-lg transition-all hover:scale-105 group"
                    title="Mark complete"
                  >
                    <CheckCircle2 className="w-4 h-4 text-white/50 group-hover:text-green-500" />
                  </button>
                </div>
              </div>
            );
          })}
        </div>
      )}
    </GlassCard>
  );

  return (
    <div className="flex-1 p-6 lg:p-8 max-w-[1000px] mx-auto w-full pt-8">
      <div className="flex flex-col mb-8">
        <div className="flex items-center gap-3 mb-2">
          <div className="p-2 bg-[var(--color-accent)]/20 rounded-xl border border-[var(--color-accent)]/30 backdrop-blur-md">
            <Bot className="w-6 h-6 text-[var(--color-accent)]" />
          </div>
          <h1 className="text-3xl font-bold tracking-tight text-white drop-shadow-md">AI Mentor Dashboard</h1>
        </div>
        <p className="text-sm text-white/50 uppercase tracking-widest font-medium ml-1">Proactive neural intel & schedule</p>
      </div>

      {/* Mentor Briefing Card */}
      <GlassCard color="rgba(168, 85, 247, 0.4)" className="mb-10">
        <div className="absolute top-0 right-0 w-64 h-64 bg-fuchsia-500/10 rounded-full mix-blend-screen blur-[80px] pointer-events-none" />

        {loadingContext ? (
          <div className="flex items-center gap-3 text-white/50 text-sm py-8 font-medium">
            <Loader2 className="w-5 h-5 animate-spin text-fuchsia-500" /> 
            Synthesizing daily cognitive blueprint from neural data...
          </div>
        ) : (
          <div className="relative z-10 py-2">
            <h3 className="text-xs font-bold text-fuchsia-400 uppercase tracking-widest mb-4 flex items-center gap-2">
               <span className="w-2 h-2 rounded-full bg-fuchsia-500 animate-pulse"></span>
               Daily Briefing
            </h3>
            <p className="text-base leading-relaxed mb-6 text-white/90 font-medium max-w-3xl">
              {briefing?.briefing || "Welcome to your Mentor Dashboard. Add skills to initiate neural tracking."}
            </p>
            {briefing?.recommendedAction && briefing.recommendedAction.targetSkill !== "None" && (
              <div className="flex items-center gap-3 inline-flex bg-white/5 border border-white/10 rounded-xl px-5 py-3 backdrop-blur-md">
                <span className="text-xs font-bold text-white/50 uppercase tracking-wider">Suggested Action:</span>
                <span className="text-xs font-bold text-fuchsia-300">{briefing.recommendedAction.type.toUpperCase()} ΓÇö {briefing.recommendedAction.targetSkill}</span>
                <ArrowRight className="w-4 h-4 text-fuchsia-400 ml-2" />
              </div>
            )}
          </div>
        )}
      </GlassCard>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div>
          <TaskSection title="Action Required Today" tasks={today} icon={Calendar} emptyText="Neural pathways are stable. No critical decay predicted today." />
        </div>
        <div>
          <TaskSection title="Upcoming Forecast (Tomorrow)" tasks={tomorrow} icon={Calendar} emptyText="No immediate decay risk tomorrow." />
          <TaskSection title="Long-Term Forecast (This Week)" tasks={week} icon={Calendar} emptyText="No structural risks this week." />
        </div>
      </div>

      {skills.length === 0 && (
        <GlassCard color="rgba(99, 102, 241, 0.1)">
          <div className="text-center py-8">
            <Calendar className="w-12 h-12 text-white/20 mx-auto mb-4" />
            <h3 className="text-lg font-bold text-white mb-2">No skills to plan for</h3>
            <p className="text-sm text-white/50">Add skills from the dashboard to see your AI-generated revision plan.</p>
          </div>
        </GlassCard>
      )}
    </div>
  );
}

"use client";

import { useState } from "react";
import { useParams, useRouter } from "next/navigation";
import { useSkills } from "@/lib/SkillContext";
import { RetentionEngine } from "@/lib/retention-engine";
import { formatDate, formatFutureDate } from "@/lib/utils";
import { ArrowLeft, BookOpen, PenTool, RefreshCw, Trash2, BrainCircuit, Goal, Clock, CheckCircle2, TrendingDown, Archive, X } from "lucide-react";
import Link from "next/link";

export default function SkillDetailPage() {
  const params = useParams();
  const router = useRouter();
  const { getSkill, markPracticed, removeSkill } = useSkills();
  const skill = getSkill(params.id as string);
  const [viewingRevision, setViewingRevision] = useState<any | null>(null);

  if (!skill) {
    return (
      <div className="flex-1 flex items-center justify-center p-8">
        <div className="text-center">
          <h2 className="text-lg font-semibold mb-2">Skill not found</h2>
          <Link href="/" className="text-sm text-[var(--color-accent)] hover:underline">Back to Dashboard</Link>
        </div>
      </div>
    );
  }

  const weakTopics = RetentionEngine.getWeakTopics(skill);
  const quizCount = skill.quizHistory.length;
  const avgAccuracy = quizCount > 0
    ? Math.round((skill.quizHistory.filter(q => q.correct).length / quizCount) * 100)
    : 0;

  const statusColors: Record<string, { ring: string; label: string; bg: string }> = {
    healthy: { ring: "stroke-[var(--color-green)]", label: "Healthy", bg: "bg-[var(--color-green-muted)] text-[var(--color-green)]" },
    review: { ring: "stroke-[var(--color-yellow)]", label: "Review Soon", bg: "bg-[var(--color-yellow-muted)] text-[var(--color-yellow)]" },
    decaying: { ring: "stroke-[var(--color-red)]", label: "Decaying", bg: "bg-[var(--color-red-muted)] text-[var(--color-red)]" },
  };

  const sc = statusColors[skill.status];
  const circumference = 2 * Math.PI * 45;
  const dashOffset = circumference - (skill.retentionScore / 100) * circumference;

  // Timeline Logic
  const levels = ["Beginner", "Intermediate", "Advanced", "Master"];
  const currentIdx = levels.indexOf(skill.proficiency) !== -1 ? levels.indexOf(skill.proficiency) : 0;
  const isMaster = currentIdx === 3;
  const canGraduate = skill.subskills.length > 0 && skill.subskills.every(s => s.strength > 85) && skill.retentionScore >= 90;

  return (
    <div className="flex-1 p-6 lg:p-8 max-w-[900px] mx-auto w-full">
      {/* Back */}
      <button onClick={() => router.push("/")} className="flex items-center gap-2 text-sm text-[var(--color-text-secondary)] hover:text-[var(--color-text-primary)] transition-colors mb-6">
        <ArrowLeft className="w-4 h-4" /> Dashboard
      </button>

      {/* Header */}
      <div className="flex items-start justify-between mb-8">
        <div>
          <h1 className="text-2xl font-bold mb-1">{skill.name}</h1>
          <p className="text-sm text-[var(--color-text-secondary)]">{skill.category} ┬╖ {skill.proficiency}</p>
        </div>
        <span className={`text-xs font-semibold px-3 py-1 rounded-full ${sc.bg}`}>{sc.label}</span>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Left: Retention Ring + Stats */}
        <div className="lg:col-span-1">
          <div className="bg-white/5 border border-white/10 backdrop-blur-md rounded-xl p-6 text-center mb-4">
            <svg width="120" height="120" className="mx-auto mb-4">
              <circle cx="60" cy="60" r="45" fill="none" stroke="var(--color-bg-card2)" strokeWidth="8" />
              <circle cx="60" cy="60" r="45" fill="none" className={sc.ring} strokeWidth="8"
                strokeDasharray={circumference} strokeDashoffset={dashOffset}
                strokeLinecap="round" transform="rotate(-90 60 60)"
                style={{ transition: "stroke-dashoffset 0.5s ease" }}
              />
              <text x="60" y="56" textAnchor="middle" className="fill-[var(--color-text-primary)] text-2xl font-bold" style={{ fontSize: "24px" }}>
                {skill.retentionScore}%
              </text>
              <text x="60" y="72" textAnchor="middle" className="fill-[var(--color-text-muted)]" style={{ fontSize: "10px" }}>
                retention
              </text>
            </svg>
            <div className="text-xs text-[var(--color-text-muted)]">
              Decay Risk: <span className="font-semibold text-[var(--color-text-secondary)]">{Math.round(skill.decayRisk * 100)}%</span>
            </div>
          </div>

          {/* Quick Stats */}
          <div className="bg-white/5 border border-white/10 backdrop-blur-md rounded-xl p-4 space-y-3">
            <div className="flex justify-between text-sm">
              <span className="text-[var(--color-text-secondary)]">Last Practiced</span>
              <span className="font-medium">{formatDate(skill.lastPracticed)}</span>
            </div>
            <div className="flex justify-between text-sm">
              <span className="text-[var(--color-text-secondary)]">Next Review</span>
              <span className="font-medium">{formatFutureDate(skill.nextReviewDate)}</span>
            </div>
            <div className="flex justify-between text-sm">
              <span className="text-[var(--color-text-secondary)]">Revisions</span>
              <span className="font-medium">{skill.revisionCount}</span>
            </div>
            <div className="flex justify-between text-sm">
              <span className="text-[var(--color-text-secondary)]">Quizzes Taken</span>
              <span className="font-medium">{quizCount}</span>
            </div>
            <div className="flex justify-between text-sm">
              <span className="text-[var(--color-text-secondary)]">Avg Accuracy</span>
              <span className="font-medium">{avgAccuracy}%</span>
            </div>
          </div>

          {/* Mastery Timeline */}
          <div className="bg-white/5 border border-white/10 backdrop-blur-md rounded-xl p-5 mt-4">
            <h3 className="text-sm font-semibold mb-4 flex items-center gap-2">
              <Goal className="w-4 h-4 text-[var(--color-accent)]" /> Mastery Timeline
            </h3>
            <div className="relative pl-3 space-y-4">
              <div className="absolute top-2 bottom-2 left-[15px] w-[2px] bg-[var(--color-border)]" />
              {levels.map((lvl, i) => {
                const isActive = i === currentIdx;
                const isPast = i < currentIdx;
                return (
                  <div key={lvl} className={`relative flex items-center gap-3 ${isPast ? 'opacity-50' : ''}`}>
                    <div className={`w-3 h-3 rounded-full z-10 shrink-0 ${
                      isActive ? "bg-[var(--color-accent)] shadow-[0_0_0_4px_rgba(99,102,241,0.2)]" : 
                      isPast ? "bg-[var(--color-green)]" : "bg-[var(--color-bg-card2)] border-2 border-[var(--color-text-muted)]"
                    }`} />
                    <span className={`text-sm ${isActive ? 'font-bold text-[var(--color-text-primary)]' : 'font-medium text-[var(--color-text-secondary)]'}`}>
                      {lvl}
                    </span>
                  </div>
                );
              })}
            </div>
            {canGraduate && !isMaster && (
              <div className="mt-4 p-3 bg-[var(--color-green-muted)] border border-[rgba(34,197,94,0.2)] rounded-lg text-center">
                <p className="text-xs font-semibold text-[var(--color-green)] mb-2">Ready for {levels[currentIdx + 1]}!</p>
                <button className="text-xs bg-[var(--color-green)] text-white px-3 py-1.5 rounded-md hover:opacity-90 transition-opacity">
                  Graduate Now
                </button>
              </div>
            )}
            {!canGraduate && !isMaster && (
              <p className="text-[10px] text-[var(--color-text-muted)] mt-4 leading-relaxed">
                Reach 90% retention and 85% strength across all subskills to graduate.
              </p>
            )}
          </div>
        </div>

        {/* Right: Weak Topics + Actions */}
        <div className="lg:col-span-2 space-y-4">
          {/* Action Buttons */}
          <div className="grid grid-cols-3 gap-3">
            <Link href={`/study?skill=${skill.id}`}
              className="flex flex-col items-center gap-2 bg-white/5 border border-white/10 backdrop-blur-md rounded-xl p-4 hover:border-[var(--color-accent-border)] transition-colors">
              <BookOpen className="w-5 h-5 text-[var(--color-accent)]" />
              <span className="text-xs font-medium">Study Notes</span>
            </Link>
            <Link href={`/quiz?skill=${skill.id}`}
              className="flex flex-col items-center gap-2 bg-white/5 border border-white/10 backdrop-blur-md rounded-xl p-4 hover:border-[var(--color-accent-border)] transition-colors">
              <PenTool className="w-5 h-5 text-[var(--color-accent)]" />
              <span className="text-xs font-medium">Take Quiz</span>
            </Link>
            <button onClick={() => markPracticed(skill.id)}
              className="flex flex-col items-center gap-2 bg-white/5 border border-white/10 backdrop-blur-md rounded-xl p-4 hover:border-[var(--color-green)] hover:border-opacity-40 transition-colors">
              <RefreshCw className="w-5 h-5 text-[var(--color-green)]" />
              <span className="text-xs font-medium">Mark Practiced</span>
            </button>
          </div>

          {/* Predictive Decay Forecast */}
          <div className="bg-white/5 border border-white/10 backdrop-blur-md rounded-xl p-5">
             <h3 className="text-sm font-semibold mb-4 flex items-center gap-2">
               <TrendingDown className="w-4 h-4 text-[var(--color-text-secondary)]" /> Decay Forecast
             </h3>
             <div className="flex gap-4">
               <div className="flex-1 bg-[var(--color-bg-card2)] border border-[var(--color-border)] rounded-lg p-3">
                 <div className="text-[10px] text-[var(--color-text-muted)] uppercase tracking-wider mb-1">In 24 Hours</div>
                 <div className="text-lg font-semibold flex items-baseline gap-1">
                   {skill.forecast24h}% <span className="text-xs font-normal text-[var(--color-text-secondary)]">retention</span>
                 </div>
               </div>
               <div className="flex-1 bg-[var(--color-bg-card2)] border border-[var(--color-border)] rounded-lg p-3">
                 <div className="text-[10px] text-[var(--color-text-muted)] uppercase tracking-wider mb-1">In 7 Days</div>
                 <div className="text-lg font-semibold flex items-baseline gap-1 text-[var(--color-red)]">
                   {skill.forecast7d}% <span className="text-xs font-normal text-[var(--color-text-secondary)]">retention</span>
                 </div>
               </div>
             </div>

             {/* Alert if critical decay in next 48 hours */}
             {new Date(skill.nextReviewDate).getTime() < Date.now() + 48*60*60*1000 && (
               <div className="mt-3 text-xs bg-[var(--color-yellow-muted)] text-[var(--color-yellow)] px-3 py-2 rounded-lg flex gap-2 items-center">
                 <Clock className="w-3.5 h-3.5" /> Core structural decay predicted within 48 hours. Reactivate pathways via Quiz.
               </div>
             )}
          </div>

          {/* Subskill Memory Map */}
          <div className="bg-white/5 border border-white/10 backdrop-blur-md rounded-xl p-5">
            <h3 className="text-sm font-semibold mb-4 flex items-center gap-2">
              <BrainCircuit className="w-4 h-4 text-[var(--color-accent)]" /> Subskill Memory Map
            </h3>
            {skill.subskills.length === 0 ? (
              <p className="text-sm text-[var(--color-text-muted)] py-4 text-center">
                Take intelligent quizzes to automatically map your localized subskill strengths.
              </p>
            ) : (
              <div className="space-y-3">
                {skill.subskills.map((sub, i) => (
                  <div key={i} className="flex items-center gap-3">
                    <span className="text-xs font-medium w-[120px] truncate">{sub.name}</span>
                    <div className="flex-1 h-2 bg-[var(--color-bg-card2)] rounded-full overflow-hidden">
                      <div className={`h-full rounded-full ${sub.strength >= 80 ? "bg-[var(--color-green)]" : sub.strength >= 50 ? "bg-[var(--color-accent)]" : "bg-[var(--color-red)]"}`} style={{ width: `${sub.strength}%` }} />
                    </div>
                    <span className="text-xs text-[var(--color-text-muted)] w-8 text-right">{sub.strength}%</span>
                  </div>
                ))}
              </div>
            )}
          </div>

          {/* Weak Topics */}
          <div className="bg-white/5 border border-white/10 backdrop-blur-md rounded-xl p-5">
            <h3 className="text-sm font-semibold mb-4">Weak Areas</h3>
            {weakTopics.length === 0 ? (
              <p className="text-sm text-[var(--color-text-muted)] py-4 text-center">
                {quizCount === 0 ? "Take a quiz to identify weak areas." : "No weaknesses detected. Keep it up!"}
              </p>
            ) : (
              <div className="space-y-2">
                {weakTopics.map((w, i) => {
                  const sevColors = {
                    critical: "bg-[var(--color-red-muted)] text-[var(--color-red)]",
                    moderate: "bg-[var(--color-yellow-muted)] text-[var(--color-yellow)]",
                    mild: "bg-[var(--color-accent-muted)] text-[var(--color-accent)]",
                  };
                  return (
                    <div key={i} className="flex items-center justify-between bg-[var(--color-bg-card2)] border border-[var(--color-border)] rounded-lg px-4 py-3">
                      <div className="flex items-center gap-3">
                        <span className="text-sm font-medium">{w.name}</span>
                        <span className={`text-[10px] font-semibold px-2 py-0.5 rounded-full ${sevColors[w.severity]}`}>
                          {w.severity}
                        </span>
                      </div>
                      <span className="text-xs text-[var(--color-text-muted)]">{w.accuracy}% accuracy</span>
                    </div>
                  );
                })}
              </div>
            )}
          </div>

          {/* Revision Vault */}
          <div className="bg-white/5 border border-white/10 backdrop-blur-md rounded-xl p-5 mt-4">
            <h3 className="text-sm font-semibold mb-4 flex items-center gap-2">
              <Archive className="w-4 h-4 text-[var(--color-accent)]" /> Revision Vault
            </h3>
            {skill.savedRevisions && skill.savedRevisions.length > 0 ? (
              <div className="space-y-3 max-h-[300px] overflow-y-auto pr-2">
                {skill.savedRevisions.map((rev) => (
                  <button 
                    key={rev.id} 
                    onClick={() => setViewingRevision(rev)}
                    className="w-full text-left bg-black/20 border border-white/5 rounded-lg p-3 flex justify-between items-center hover:border-cyan-500/50 hover:bg-cyan-500/5 transition-all outline-none"
                  >
                    <div>
                      <div className="text-sm font-semibold text-white/90">{rev.title}</div>
                      <div className="text-[10px] text-white/40 mt-1">{formatDate(rev.createdAt)}</div>
                    </div>
                    <span className="text-[10px] font-bold uppercase tracking-widest px-2 py-1 bg-white/10 rounded-full text-white/70">{rev.type}</span>
                  </button>
                ))}
              </div>
            ) : (
              <p className="text-sm text-white/30 py-4 text-center">
                Generate study notes, flashcards, or scenarios to automatically store them here for future revision.
              </p>
            )}
          </div>

          {/* Delete */}
          <button
            onClick={() => { removeSkill(skill.id); router.push("/"); }}
            className="flex items-center gap-2 text-xs text-[var(--color-text-muted)] hover:text-[var(--color-red)] transition-colors mt-4"
          >
            <Trash2 className="w-3.5 h-3.5" /> Remove this skill
          </button>
        </div>
      </div>

      {/* Basic Revision Viewer Modal */}
      {viewingRevision && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
          <div className="bg-zinc-900 border border-white/10 w-full max-w-3xl max-h-[80vh] rounded-2xl flex flex-col shadow-2xl overflow-hidden relative">
            <div className="p-4 border-b border-white/10 flex justify-between items-center bg-zinc-900/50">
              <div>
                <h3 className="text-lg font-bold text-white">{viewingRevision.title}</h3>
                <span className="text-xs text-white/50">{formatDate(viewingRevision.createdAt)}</span>
              </div>
              <button onClick={() => setViewingRevision(null)} className="p-2 text-white/50 hover:text-white transition-colors bg-white/5 rounded-full">
                <X className="w-5 h-5" />
              </button>
            </div>
            <div className="p-6 overflow-y-auto text-sm text-white/80 leading-relaxed">
              <pre className="whitespace-pre-wrap font-sans">
                {JSON.stringify(viewingRevision.content, null, 2)}
              </pre>
            </div>
          </div>
        </div>
      )}

    </div>
  );
}

"use client";

import { useState, useEffect, useRef } from "react";
import { useSearchParams } from "next/navigation";
import { useSkills } from "@/lib/SkillContext";
import type { GeneratedNotes } from "@/lib/types";
import { Loader2, BookOpen, Send, Bot, User, Sparkles, MessageCircle, ChevronDown, ChevronUp } from "lucide-react";
import { AnimatedAIChat } from "@/components/ui/AnimatedAIChat";

export default function StudyWorkspace() {
  const searchParams = useSearchParams();
  const { skills, getSkill, markPracticed, saveRevision } = useSkills();
  const [selectedSkillId, setSelectedSkillId] = useState(searchParams.get("skill") || "");
  const [notes, setNotes] = useState<GeneratedNotes | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [activeChapter, setActiveChapter] = useState(0);

  // Chatbot state
  const [chatMessages, setChatMessages] = useState<{ role: string; content: string }[]>([]);
  const [chatLoading, setChatLoading] = useState(false);

  const selectedSkill = selectedSkillId ? getSkill(selectedSkillId) : undefined;

  const generateNotes = async () => {
    if (!selectedSkill) return;
    setLoading(true);
    setError(null);
    try {
      const res = await fetch("/api/generate-notes", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ 
          skill: selectedSkill.name, 
          proficiency: selectedSkill.proficiency,
          weakTopics: selectedSkill.weakTopics,
          quizHistory: selectedSkill.quizHistory
        }),
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error);
      setNotes(data.notes);
      saveRevision(selectedSkill.id, {
        type: "notes",
        title: `Study Notes: ${selectedSkill.name}`,
        content: data.notes
      });
      setActiveChapter(0);
      markPracticed(selectedSkill.id);
    } catch (e) {
      setError(e instanceof Error ? e.message : "Failed to generate notes");
    } finally {
      setLoading(false);
    }
  };

  const sendChat = async (text: string) => {
    const msg = text;
    if (!msg.trim() || chatLoading) return;

    const newMessages = [...chatMessages, { role: "user", content: msg }];
    setChatMessages(newMessages);
    setChatLoading(true);

    try {
      const res = await fetch("/api/study-buddy", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          messages: newMessages,
          skillContext: selectedSkill ? {
            skill: selectedSkill.name,
            proficiency: selectedSkill.proficiency,
            weakAreas: selectedSkill.weakTopics,
          } : undefined,
        }),
      });
      const data = await res.json();
      setChatMessages(prev => [...prev, { role: "assistant", content: data.message }]);
    } catch {
      setChatMessages(prev => [...prev, { role: "assistant", content: "Sorry, I couldn't process that. Try again." }]);
    } finally {
      setChatLoading(false);
    }
  };

  return (
    <div className="flex-1 flex h-screen overflow-hidden">
      {/* Left: Notes Panel */}
      <div className="flex-1 flex flex-col overflow-hidden">
        {/* Header */}
        <div className="shrink-0 p-6 pb-0">
          <h1 className="text-xl font-bold mb-1">Study Workspace</h1>
          <p className="text-sm text-[var(--color-text-secondary)] mb-4">Generate structured study material for any skill</p>

          <div className="flex items-center gap-3 mb-4">
            <select
              value={selectedSkillId}
              onChange={(e) => { setSelectedSkillId(e.target.value); setNotes(null); }}
              className="flex-1 bg-[var(--color-bg-card)] border border-[var(--color-border)] rounded-lg px-3 py-2.5 text-sm outline-none focus:border-[var(--color-accent)] transition-colors"
            >
              <option value="">Select a skill...</option>
              {skills.map(s => <option key={s.id} value={s.id}>{s.name} ({s.proficiency})</option>)}
            </select>
            <button
              onClick={generateNotes}
              disabled={!selectedSkillId || loading}
              className="bg-[var(--color-accent)] hover:bg-[var(--color-accent-hover)] text-white px-5 py-2.5 rounded-lg text-sm font-medium transition-colors disabled:opacity-40 flex items-center gap-2"
            >
              {loading ? <Loader2 className="w-4 h-4 animate-spin" /> : <BookOpen className="w-4 h-4" />}
              Generate Notes
            </button>
          </div>
        </div>

        {/* Notes Content */}
        <div className="flex-1 overflow-y-auto px-6 pb-6">
          {!notes && !loading && (
            <div className="flex flex-col items-center justify-center py-20 text-center">
              <BookOpen className="w-10 h-10 text-[var(--color-text-muted)] mb-4" />
              <h3 className="text-base font-semibold mb-1">No notes generated yet</h3>
              <p className="text-sm text-[var(--color-text-muted)] max-w-sm">Select a skill and click Generate Notes to create structured study material.</p>
            </div>
          )}

          {loading && (
            <div className="flex flex-col items-center justify-center py-20">
              <Loader2 className="w-8 h-8 text-[var(--color-accent)] animate-spin mb-4" />
              <p className="text-sm text-[var(--color-text-secondary)]">Generating comprehensive study notes...</p>
            </div>
          )}

          {error && (
            <div className="bg-[var(--color-red-muted)] border border-[rgba(239,68,68,0.2)] rounded-lg p-4 text-sm text-[var(--color-red)]">{error}</div>
          )}

          {notes && !loading && (
            <div className="space-y-6">
              {/* Overview */}
              <div className="bg-[var(--color-bg-card)] border border-[var(--color-border)] rounded-xl p-5">
                <h2 className="text-lg font-bold mb-2">{notes.skill} ΓÇö Study Guide</h2>
                <p className="text-sm text-[var(--color-text-secondary)] leading-relaxed">{notes.overview}</p>
                <div className="flex gap-2 mt-3 flex-wrap">
                  <span className="text-[10px] font-semibold px-2 py-0.5 rounded-full bg-[var(--color-accent-muted)] text-[var(--color-accent)]">{notes.proficiency}</span>
                  <span className="text-[10px] font-semibold px-2 py-0.5 rounded-full bg-[var(--color-bg-card2)] text-[var(--color-text-muted)]">{notes.model}</span>
                </div>
              </div>

              {/* Prerequisites */}
              {notes.prerequisites.length > 0 && (
                <div className="bg-[var(--color-bg-card)] border border-[var(--color-border)] rounded-xl p-5">
                  <h3 className="text-sm font-semibold mb-3">Prerequisites</h3>
                  <ul className="space-y-1.5">
                    {notes.prerequisites.map((p, i) => (
                      <li key={i} className="text-sm text-[var(--color-text-secondary)] flex items-start gap-2">
                        <span className="text-[var(--color-accent)] mt-0.5">ΓÇó</span> {p}
                      </li>
                    ))}
                  </ul>
                </div>
              )}

              {/* Chapters */}
              <div className="bg-[var(--color-bg-card)] border border-[var(--color-border)] rounded-xl overflow-hidden">
                {/* Chapter Nav */}
                <div className="flex border-b border-[var(--color-border)] overflow-x-auto">
                  {notes.chapters.map((ch, i) => (
                    <button
