"use client";

import { CSSProperties, useRef, ReactNode, useId } from "react";
import { useGSAP } from "@gsap/react";
import gsap from "gsap";
import { cn } from "@/lib/utils";

type LiquidGlassProps = {
    width?: number | string;
    height?: number | string;
    borderRadius?: number;
    tintOpacity?: number;
    blur?: number;
    children?: ReactNode;
    className?: string;
};

export const LiquidGlass = (props: LiquidGlassProps) => {
    const { width = "100%", height = "100%", borderRadius = 12, tintOpacity = 0.05, blur = 10, children, className } = props;

    const glassRef = useRef<HTMLDivElement>(null);

    const filterId = `glass-distortion-${useId().replace(/:/g, "")}`;

    useGSAP(() => {
        const glass = glassRef.current;
        const parent = glass?.parentElement;

        if (!glass || !parent) return;

        const mouseMove = (e: MouseEvent) => {
            if (!glassRef.current || !glassRef.current?.parentElement) return;

            const parentRect = parent.getBoundingClientRect();

            // Adjust to track center
            const posX = e.clientX - parentRect.left - parentRect.width / 2;
            const posY = e.clientY - parentRect.top - parentRect.height / 2;

            gsap.to(glassRef.current, {
                duration: 0.6,
                x: posX * 0.1, // Slight parallax
                y: posY * 0.1,
                ease: "power2.out",
            });
        };

        if (parent) {
            parent.addEventListener("mousemove", mouseMove);
            // reset on leave
            parent.addEventListener("mouseleave", () => {
                gsap.to(glassRef.current, { duration: 0.6, x: 0, y: 0, ease: "power2.out" });
            });
        }

        return () => {
            if (parent) {
                parent.removeEventListener("mousemove", mouseMove);
            }
        };
    }, []);

    return (
        <div className={cn("relative overflow-hidden group/liquid", className)} style={{ borderRadius: `${borderRadius}px` }}>
            <svg xmlns="http://www.w3.org/2000/svg" width="0" height="0" className="absolute overflow-hidden">
                <defs>
                    <filter id={filterId} x="0%" y="0%" width="100%" height="100%">
                        <feTurbulence
                            type="fractalNoise"
                            baseFrequency="0.008 0.008"
                            numOctaves="2"
                            seed="92"
                            result="noise"></feTurbulence>
                        <feGaussianBlur in="noise" stdDeviation="2" result="blurred"></feGaussianBlur>
                        <feDisplacementMap
                            in="SourceGraphic"
                            in2="blurred"
                            scale="40"
                            xChannelSelector="R"
                            yChannelSelector="G"></feDisplacementMap>
                    </filter>
                </defs>
            </svg>
            <div
                ref={glassRef}
                className={cn(
                    "absolute isolate z-0 transition-transform duration-300",
                    [
                        "before:absolute before:inset-0 before:z-0 before:rounded-[var(--lg-border-radius)] before:bg-[rgba(255,255,255,var(--lg-tint-opacity))] before:content-['']",
                    ],
                    [
                        `after:absolute after:-inset-4 after:isolate after:-z-1 after:rounded-[var(--lg-border-radius)] after:[filter:url(#${filterId})_blur(var(--lg-blur))] after:content-['']`,
                    ],
                )}
                style={
                    {
                        "--lg-border-radius": `${borderRadius}px`,
                        "--lg-tint-opacity": tintOpacity,
                        "--lg-blur": `${blur}px`,
                        width: "120%",
                        height: "120%",
                        top: "-10%",
                        left: "-10%",
                    } as CSSProperties
                }></div>
            <div className="relative z-10 w-full h-full bg-white/5 border border-white/10 p-5 rounded-[inherit] backdrop-blur-md shadow-2xl">
                {children}
            </div>
        </div>
    );
};

"use client";

import React, { Component, ErrorInfo, ReactNode } from "react";
import dynamic from "next/dynamic";

const Spline = dynamic(() => import("@splinetool/react-spline"), { 
  ssr: false,
  loading: () => null
});

interface SplineSceneProps {
  scene: string
  className?: string
}

class SplineErrorBoundary extends Component<{ children: ReactNode }, { hasError: boolean }> {
  constructor(props: { children: ReactNode }) {
    super(props);
    this.state = { hasError: false };
  }

  static getDerivedStateFromError(_: Error) {
    return { hasError: true };
  }

  componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.warn("Spline integration failed to load gracefully. Ignoring buffer error.", error);
  }

  render() {
    if (this.state.hasError) {
      return null; // Fallback entirely, the background CSS will still show.
    }
    return this.props.children;
  }
}

export function SplineScene({ scene, className }: SplineSceneProps) {
  return (
    <div className={className}>
      <SplineErrorBoundary>
        <Spline scene={scene} />
      </SplineErrorBoundary>
    </div>
  )
}

"use client";

import React, { useRef } from "react";
import { motion, useMotionValue, useSpring, useTransform } from "framer-motion";
import { cn } from "@/lib/utils";

export const TiltCard = ({
  children,
  className,
  ...props
}: {
  children: React.ReactNode;
  className?: string;
  onClick?: () => void;
  [key: string]: any;
}) => {
  const ref = useRef<HTMLDivElement>(null);
  const x = useMotionValue(0);
  const y = useMotionValue(0);

  // Soft physics for rotation
  const mouseXSpring = useSpring(x, { stiffness: 150, damping: 20 });
  const mouseYSpring = useSpring(y, { stiffness: 150, damping: 20 });

  const rotateX = useTransform(mouseYSpring, [-0.5, 0.5], ["7deg", "-7deg"]);
  const rotateY = useTransform(mouseXSpring, [-0.5, 0.5], ["-7deg", "7deg"]);
  // Optional glare effect transform
  const glareX = useTransform(mouseXSpring, [-0.5, 0.5], ["100%", "-100%"]);
  const glareY = useTransform(mouseYSpring, [-0.5, 0.5], ["100%", "-100%"]);

  const handleMouseMove = (e: React.MouseEvent<HTMLDivElement>) => {
    if (!ref.current) return;
    const rect = ref.current.getBoundingClientRect();
    const width = rect.width;
    const height = rect.height;
    const mouseX = e.clientX - rect.left;
    const mouseY = e.clientY - rect.top;
    x.set(mouseX / width - 0.5);
    y.set(mouseY / height - 0.5);
  };

  const handleMouseLeave = () => {
    x.set(0);
    y.set(0);
  };

  return (
    <motion.div
      ref={ref}
      onMouseMove={handleMouseMove}
      onMouseLeave={handleMouseLeave}
      style={{
        rotateX,
        rotateY,
        transformStyle: "preserve-3d",
      }}
      className={cn(
        "relative rounded-[2rem] bg-white/5 border border-white/10 backdrop-blur-xl shadow-2xl transition-all hover:border-cyan-500/30 overflow-hidden group",
        className
      )}
      {...props}
    >
      {/* Glare Reflection */}
      <motion.div
        className="absolute inset-0 z-0 pointer-events-none opacity-0 group-hover:opacity-100 transition-opacity duration-300 pointer-events-none"
        style={{
          background: "radial-gradient(circle at center, rgba(255,255,255,0.1) 0%, transparent 60%)",
          x: glareX,
          y: glareY,
        }}
      />
      {/* Ambient Glow */}
      <div className="absolute inset-0 z-0 pointer-events-none opacity-0 group-hover:opacity-100 transition-opacity duration-700 bg-gradient-to-br from-cyan-500/5 via-transparent to-indigo-500/5" />

      <div className="relative z-10 w-full h-full p-6 lg:p-8" style={{ transform: "translateZ(40px)" }}>
        {children}
      </div>
    </motion.div>
  );
};

